import { Document, Schema, model } from 'mongoose';
import { ObjectId } from 'mongodb';

export interface Group extends Document {
  id: ObjectId;
  name: string;
  description: string;
  adminId: ObjectId;
  members: ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const GroupSchema = new Schema<Group>(
  {
    name: { type: String, required: true },
    description: { type: String, required: true },
    adminId: { type: Schema.Types.ObjectId, required: true },
    members: { type: [Schema.Types.ObjectId], default: [] },
    telegramChatId: { type: String, required: false },
    createdAt: { type: Date, default: Date.now },
  },
  {
    timestamps: true,
  }
);

export const GroupModel = model<Group>('Group', GroupSchema);

import { Group, GroupModel } from './group.model';

export class GroupRepository {
  async createGroup(group: Pick<Group, 'name' | 'description' | 'adminId'>): Promise<Group> {
    const newGroup = new GroupModel(group);
    return newGroup.save();
  }

  async findGroupById(groupId: string): Promise<Group | null> {
    return GroupModel.findById(groupId).exec();
  }

  async linkTelegram(groupId: string, telegramChatId: string): Promise<Group | null> {
    return GroupModel.findByIdAndUpdate(groupId, { telegramChatId }, { new: true }).exec();
  }
}

import { GroupRepository } from './group.repository';
import { Group } from './group.model';

export class GroupService {
  constructor(private groupRepository: GroupRepository) {}

  async createGroup(name: string, description: string, adminId: string): Promise<Group> {
    return this.groupRepository.createGroup({ name, description, adminId });
  }

  async getGroupById(groupId: string): Promise<Group | null> {
    return this.groupRepository.findGroupById(groupId);
  }

  async linkTelegramChat(groupId: string, telegramChatId: string): Promise<Group | null> {
    return this.groupRepository.linkTelegram(groupId, telegramChatId);
  }
}

import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { GroupValidators } from './group.validator';
import { AppError } from '../../utils/app-error';

export class GroupController {
  constructor(private groupService: GroupService) {}

  async createGroup(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      GroupValidators.createGroup.parse(req.body);

      const { name, description, adminId } = req.body;
      const group = await this.groupService.createGroup(name, description, adminId);
      res.status(201).json({
        success: true,
        data: group,
        meta: {
          requestId: req.headers['x-request-id'] || '',
          timestamp: new Date().toISOString(),
          version: 'v1',
        },
      });
    } catch (error) {
      next(new AppError(400, 'Invalid request', error));
    }
  }

  async getGroupById(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const group = await this.groupService.getGroupById(req.params.id);
      if (!group) throw new AppError(404, 'Group not found');

      res.json({
        success: true,
        data: group,
        meta: {
          requestId: req.headers['x-request-id'] || '',
          timestamp: new Date().toISOString(),
          version: 'v1',
        },
      });
    } catch (error) {
      next(error);
    }
  }

  async linkTelegram(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      GroupValidators.linkTelegram.parse(req.body);
      const { telegramChatId } = req.body;
      const group = await this.groupService.linkTelegramChat(req.params.id, telegramChatId);
      if (!group) throw new AppError(404, 'Group not found');

      res.json({
        success: true,
        data: group,
        meta: {
          requestId: req.headers['x-request-id'] || '',
          timestamp: new Date().toISOString(),
          version: 'v1',
        },
      });
    } catch (error) {
      next(error);
    }
  }
}

import { z } from 'zod';

export const GroupValidators = {
  createGroup: z.object({
    name: z.string().min(1),
    description: z.string().min(1),
    adminId: z.string().regex(/^[a-fA-F0-9]{24}$/), // Ensuring it's a valid ObjectId
  }),

  linkTelegram: z.object({
    telegramChatId: z.string().min(1),
  }),
};

export class AppError extends Error {
  statusCode: number;
  code: string;

  constructor(statusCode: number, message: string, code: string) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
    Error.captureStackTrace(this, this.constructor);
  }
}
